import numpy as np
import csv
import re
from pathlib import Path
from scipy.optimize import least_squares

def parse_param(col):
    text = col.strip()
    m = re.search(r'(\d+(?:\.\d+)?)\s*uM', text, re.IGNORECASE)
    if m: return float(m.group(1))
    m = re.search(r'(\d+(?:\.\d+)?)\s*mM', text, re.IGNORECASE)
    if m: return float(m.group(1)) * 1000.0
    m = re.search(r'(\d+(?:\.\d+)?)\s*mg/mL', text, re.IGNORECASE)
    if m: return float(m.group(1))
    m = re.search(r'(\d+(?:\.\d+)?)\s*ng/ul', text, re.IGNORECASE)
    if m: return float(m.group(1))
    m = re.search(r'pH\s+(\d+(?:\.\d+)?)', text, re.IGNORECASE)
    if m: return float(m.group(1))
    m = re.search(r'(\d+(?:\.\d+)?)\s*%', text)
    if m: return float(m.group(1))
    m = re.search(r':\s*(\d+(?:\.\d+)?)\s*$', text)
    if m: return float(m.group(1))
    return None

def load_tsv(path):
    with open(path, newline='') as f:
        reader = csv.reader(f, delimiter='\t')
        header = next(reader)
        response_headers = header[1:]
        parsed_params = [parse_param(h) for h in response_headers]
        if all(p is not None for p in parsed_params):
            parameters = [float(p) for p in parsed_params]
        else:
            parameters = [float(i+1) for i in range(len(response_headers))]
        features, targets = [], []
        for row in reader:
            if not row: continue
            meas_x = float(row[0])
            for param, value in zip(parameters, row[1:]):
                if value == '' or value.strip().lower() == 'nan': continue
                features.append([meas_x, param])
                targets.append(float(value))
    return np.array(features), np.array(targets)

def nmse(y_true, y_pred):
    if not np.all(np.isfinite(y_pred)):
        return float('inf')
    var = float(np.var(y_true))
    if var <= 0.0:
        return float(np.mean((y_true - y_pred)**2))
    return float(np.mean((y_true - y_pred)**2) / var)

# Look at the worst datasets more carefully
paths = {
    'seeded_insulin': '/home/mrsar/protein-ag/past-published-data/disease-relevant non-inhibited/insulin/Fits/Nielsen2001_seeded_sec/fit.tsv',
    'kar2011_Q37_sec': '/home/mrsar/protein-ag/past-published-data/disease-relevant non-inhibited/htt/Kar2011/Fits/Kar2011_Q37_sec/fit.tsv',
    'kar2011_Q37_prim': '/home/mrsar/protein-ag/past-published-data/disease-relevant non-inhibited/htt/Kar2011/Fits/Kar2011_Q37_prim/fit.tsv',
}

for name, path in paths.items():
    X, y = load_tsv(path)
    x1_vals = np.unique(X[:,1])
    t_vals = np.unique(X[:,0])
    print(f'{name}:')
    print(f'  x1 unique values: {x1_vals}')
    print(f'  t range: {X[:,0].min():.1f} to {X[:,0].max():.1f}')
    print(f'  y range: {y.min():.6f} to {y.max():.6f}')

    # For each x1 value, show the sigmoidal shape
    for x1v in x1_vals[:3]:
        mask = X[:,1] == x1v
        t_sub = X[mask, 0]
        y_sub = y[mask]
        sort_idx = np.argsort(t_sub)
        t_sub = t_sub[sort_idx]
        y_sub = y_sub[sort_idx]
        idx10 = np.argmin(np.abs(y_sub - 0.1))
        idx50 = np.argmin(np.abs(y_sub - 0.5))
        idx90 = np.argmin(np.abs(y_sub - 0.9))
        print(f'  x1={x1v}: t_10={t_sub[idx10]:.0f}, t_50={t_sub[idx50]:.0f}, t_90={t_sub[idx90]:.0f}')
    print()
" 2>/dev/null

